mapper.select:
/* AdminUserMapper.selectAdminUserList */ SELECT A.USER_ID, A.USER_NM, CONVERT(AES_DECRYPT(UNHEX(A.USER_TEL), 'RSOS') USING utf8) AS USER_TEL, CONVERT(AES_DECRYPT(UNHEX(A.USER_MAIL), 'RSOS') USING utf8) AS USER_MAIL, A.USER_PWD, A.USER_AUTH, A.DEPT_CD, GROUP_CONCAT( DISTINCT CASE WHEN B.CD_CODE = 'ATH300' THEN CONCAT( B.CD_CODE_NM, '(', CASE A.BIZ_DIV_CD WHEN 'APPLY' THEN '처리' WHEN 'RECEIPT' THEN '접수' ELSE '' END, ')' ) ELSE B.CD_CODE_NM END ORDER BY B.CD_CODE SEPARATOR ',' ) AS USER_AUTH_NM,
GROUP_CONCAT(DISTINCT AUS.site_cd ORDER BY AUS.site_cd SEPARATOR ',') AS SITE_CD_LIST, MAX(A.BIZ_DIV_CD) AS BIZ_DIV_CD FROM ADMIN_USER A LEFT JOIN admin_user_site AUS ON AUS.user_id = A.USER_ID LEFT JOIN CD_COMMON B ON B.cd_div = '003' AND FIND_IN_SET(B.CD_CODE, A.USER_AUTH)
WHERE 1=1
GROUP BY A.USER_ID, A.USER_NM, A.USER_PWD, A.USER_AUTH
ORDER BY A.USER_ID LIMIT #{offset}, #{pageSize}

mapper.sql:
AND a.use_yn = 1

    AND (
    A.USER_ID LIKE CONCAT('%', #{searchKeyword}, '%')
    OR A.USER_NM LIKE CONCAT('%', #{searchKeyword}, '%')
    )



    AND FIND_IN_SET(#{searchRole}, A.USER_AUTH)


    AND A.DEPT_CD = #{searchDeptCd}




    AND EXISTS (
    SELECT 1
    FROM admin_user_site AUS2
    WHERE AUS2.user_id = A.USER_ID
    AND AUS2.site_cd = #{searchSiteCd}
    )


    AND EXISTS (
    SELECT 1
    FROM admin_user_site AUS1
    WHERE AUS1.user_id = A.USER_ID
    AND AUS1.site_cd IN

        #{siteCd}

    )

