/* AdminUserMapper.deleteAdminUser - 관리자 삭제  */
UPDATE ADMIN_USER
SET USE_YN = 0,
    UPD_DT = NOW(),
    UPD_ID = #{updateStaff}

WHERE USER_ID = #{userId}

