SELECT CAST(AES_DECRYPT(UNHEX(A.USER_TEL), 'RSOS') AS CHAR) AS cellPhone , a.user_id AS userId FROM ADMIN_USER A LEFT JOIN admin_user_site AUS ON AUS.user_id = A.USER_ID WHERE AUS.site_cd = #{siteCd}
AND A.BIZ_DIV_CD = #{bizDivCd}
AND A.USE_YN = 1

